function PlatformIcon({ name }: { name: string }) {
  const path = PLATFORM_ICONS[name];
  // Platforms without a verified glyph get a muted monogram tile that fills the
  // same slot as a real logo, so every cell reads as intentional and aligned
  // rather than a loud dot floating next to the brand marks.
  if (!path) {
    return (
      <span
        aria-hidden="true"
        className="bg-elevated text-muted/80 flex size-3.5 shrink-0 items-center justify-center rounded-[3px] text-[0.55rem] leading-none font-semibold"
      >
        {name.charAt(0)}
      </span>
    );
  }
  return (
    <svg
      aria-hidden="true"
      className="size-3.5 shrink-0"
      fill="currentColor"
      role="img"
      viewBox="0 0 24 24"
    >
      <path d={path} />
    </svg>
  );
}

function VisualCard({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "border-border bg-card/70 cta-panel-frame rounded-2xl border p-6",
        className,
      )}
    >
      {children}
    </div>
  );
}

function StatLine({ value, label }: { value: string; label: string }) {
  return (
    <p className="flex items-baseline gap-2">
      <span className="font-display text-foreground text-5xl font-bold tracking-tight tabular-nums">
        {value}
      </span>
      <span className="text-muted text-sm">{label}</span>
    </p>
  );
}

function PlatformChip({ name }: { name: string }) {
  return (
    <span className="border-border bg-elevated/60 text-foreground hover:text-brand inline-flex items-center gap-2 rounded-lg border px-3 py-1.5 text-xs font-medium transition-all hover:border-[color-mix(in_oklch,var(--brand)_40%,var(--border))] hover:bg-[color-mix(in_oklch,var(--paper),var(--brand)_4%)] hover:shadow-[0_0_0_1px_color-mix(in_oklch,var(--brand)_20%,transparent),0_8px_26px_-8px_color-mix(in_oklch,var(--brand)_38%,transparent)]">
      <PlatformIcon name={name} />
      {name}
    </span>
  );
}

function PlatformStatCard() {
  return (
    <VisualCard>
      <StatLine label="platforms" value="65+" />
      <ul className="mt-4 flex flex-wrap gap-2">
        {["Twitch", "YouTube", "TikTok", "Instagram", "Kick", "Twitter"].map(
          (name) => (
            <li key={name}>
              <PlatformChip name={name} />
            </li>
          ),
        )}
        <li>
          <span className="border-brand/50 bg-brand/10 text-brand-soft inline-flex items-center rounded-lg border px-3 py-1.5 text-xs font-medium">
            +59 more
          </span>
        </li>
      </ul>
    </VisualCard>
  );
}

function PlatformExplorer() {
  const [category, setCategory] = useState<"all" | PlatformCategory>("all");

  const visible =
    category === "all"
      ? PLATFORMS
      : PLATFORMS.filter((platform) => platform.categories.includes(category));

  return (
    <div className="mt-8">
      <div
        aria-label="Filter platforms by category"
        className="flex flex-wrap gap-2"
        role="group"
      >
        {PLATFORM_CATEGORIES.map((item) => {
          const isActive = category === item.id;
          return (
            <button
              aria-pressed={isActive}
              className={cn(
                "focus-visible:ring-ring/60 rounded-full border px-3.5 py-1.5 text-xs font-medium transition-colors outline-none focus-visible:ring-3",
                isActive
                  ? "border-brand bg-brand text-white"
                  : "border-border bg-card/60 text-muted hover:text-foreground",
              )}
              key={item.id}
              onClick={() => setCategory(item.id)}
              type="button"
            >
              {item.label}
            </button>
          );
        })}
      </div>

      <ul className="mt-4 grid grid-cols-2 gap-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6">
        {visible.map((platform) => (
          <li className="flex" key={platform.name}>
            <span className="border-border bg-card/60 text-foreground hover:text-brand flex min-h-[2.75rem] w-full items-center gap-2.5 rounded-lg border px-2.5 py-2 text-left text-xs leading-tight font-medium transition-all hover:border-[color-mix(in_oklch,var(--brand)_40%,var(--border))] hover:bg-[color-mix(in_oklch,var(--paper),var(--brand)_4%)] hover:shadow-[0_0_0_1px_color-mix(in_oklch,var(--brand)_20%,transparent),0_8px_26px_-8px_color-mix(in_oklch,var(--brand)_38%,transparent)]">
              <PlatformIcon name={platform.name} />
              <span className="min-w-0">{platform.name}</span>
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}

